  1267→        mileageStdDevKm: Math.round(Number(stats.stdDevMileageKm) || 0),
  1268→      };
  1269→
  1270→      span.setAttribute('stats.totalTrains', result.totalTrains);
  1271→      span.setAttribute('stats.fitTrains', result.fitTrains);
  1272→      span.setAttribute('stats.avgMileage', result.averageMileageKm);
