  1562→  /**
  1563→   * Create a new component
  1564→   */
  1565→  async createComponent(data: NewTrainComponent): Promise<TrainComponent> {
  1566→    return this.inTransaction('createComponent', async (tx, span) => {
  1567→      span.setAttribute('component.serialNumber', data.serialNumber);
  1568→      span.setAttribute('component.type', data.componentType);
  1569→
  1570→      // Check for duplicate serial number
  1571→      const existing = await tx.query.trainComponents.findFirst({
  1572→        where: eq(trainComponents.serialNumber, data.serialNumber),
  1573→      });
  1574→
  1575→      if (existing) {
  1576→        throw new DuplicateError(`Component with serial number ${data.serialNumber} already exists`, {
  1577→          field: 'serialNumber',
  1578→          value: data.serialNumber,
  1579→        });
  1580→      }
  1581→
  1582→      // Validate current train if provided
  1583→      if (data.currentTrainId) {
  1584→        const train = await tx.query.trains.findFirst({
  1585→          where: eq(trains.id, data.currentTrainId),
