  1589→            field: 'currentTrainId',
  1590→            context: { trainId: data.currentTrainId },
  1591→          });
  1592→        }
  1593→      }
  1594→
  1595→      const [result] = await tx.insert(trainComponents).values(data).returning();
  1596→      span.setAttribute('component.id', result.id);
  1597→
  1598→      this.log.info(
  1599→        { componentId: result.id, serialNumber: data.serialNumber, type: data.componentType },
  1600→        'Component created'
  1601→      );
  1602→      return result;
  1603→    });
  1604→  }
