  1606→  /**
  1607→   * Update an existing component
  1608→   */
  1609→  async updateComponent(id: string, data: Partial<NewTrainComponent>): Promise<TrainComponent> {
  1610→    return this.inTransaction('updateComponent', async (tx, span) => {
  1611→      span.setAttribute('component.id', id);
