  1614→        where: eq(trainComponents.id, id),
  1615→      });
  1616→
  1617→      if (!existing) {
  1618→        throw new NotFoundError(`Component not found: ${id}`, {
  1619→          entityType: 'component',
  1620→          entityId: id,
  1621→        });
  1622→      }
  1623→
  1624→      // Check for duplicate serial number if changing
  1625→      if (data.serialNumber && data.serialNumber !== existing.serialNumber) {
  1626→        const duplicate = await tx.query.trainComponents.findFirst({
  1627→          where: eq(trainComponents.serialNumber, data.serialNumber),
  1628→        });
  1629→        if (duplicate) {
