  1497→  /**
  1498→   * Unlock a PM to allow optimizer changes.
  1499→   */
  1500→  async unlockPm(pmScheduleId: string, unlockedBy: string): Promise<PmScheduleRecord> {
  1501→    return this.inTransaction('unlockPm', async (tx, span) => {
  1502→      span.setAttribute('pm.scheduleId', pmScheduleId);
  1503→
  1504→      const existing = await tx.query.pmSchedule.findFirst({
  1505→        where: eq(pmSchedule.id, pmScheduleId),
  1506→      });
  1507→
  1508→      if (!existing) {
  1509→        throw new PmScheduleNotFoundError(pmScheduleId);
  1510→      }
  1511→
  1512→      if (!existing.isLocked) {
  1513→        throw new BusinessRuleError('PM is not locked', {
  1514→          rule: 'pm_not_locked',
  1515→        });
  1516→      }
  1517→
  1518→      // Cannot unlock if Maximo work order is in progress
  1519→      if (existing.maximoWoId && existing.status === 'IN_PROGRESS') {
  1520→        throw new MaximoLockError(
  1521→          'Cannot unlock PM with in-progress Maximo work order',
  1522→          {
  1523→            workOrderId: existing.maximoWoId,
  1524→            maximoStatus: 'INPRG',
  1525→          }
  1526→        );
  1527→      }
  1528→
  1529→      const [updated] = await tx
  1530→        .update(pmSchedule)
  1531→        .set({
  1532→          isLocked: false,
  1533→          lockedReason: null,
  1534→          lockedBy: null,
  1535→          lockedAt: null,
  1536→          updatedAt: new Date(),
  1537→        })
  1538→        .where(eq(pmSchedule.id, pmScheduleId))
  1539→        .returning();
  1540→
  1541→      // Create audit history
  1542→      const historyRecord: NewPmScheduleHistory = {
  1543→        pmScheduleId,
  1544→        changeType: 'UNLOCKED',
  1545→        changedBy: unlockedBy,
  1546→        changeReason: 'Manual unlock',
  1547→        changeSource: 'USER',
  1548→      };
  1549→
  1550→      await tx.insert(pmScheduleHistory).values(historyRecord);
  1551→
  1552→      this.log.info(
  1553→        { pmScheduleId, unlockedBy },
  1554→        `PM unlocked: ${pmScheduleId}`
  1555→      );
  1556→
  1557→      return updated;
  1558→    });
  1559→  }
