  1561→  // ===========================================================================
  1562→  // Tactical Scheduling Run
  1563→  // ===========================================================================
  1564→
  1565→  /**
  1566→   * Run tactical scheduling for the 12-week horizon.
  1567→   *
  1568→   * This method:
  1569→   * 1. Calculates PM due dates for all trains in scope
  1570→   * 2. Prioritizes by overdue status and due date
  1571→   * 3. Attempts to schedule each PM respecting constraints
  1572→   * 4. Returns a detailed result with scheduled, deferred, and blocked PMs
  1573→   */
  1574→  async runTacticalSchedule(request: TacticalScheduleRequest): Promise<SchedulingResult> {
  1575→    return this.traced('runTacticalSchedule', async (span) => {
  1576→      const {
  1577→        fleetId,
  1578→        depotId,
  1579→        horizonWeeks = DEFAULT_HORIZON_WEEKS,
  1580→        dryRun = false,
  1581→        respectLocks = true,
  1582→      } = request;
  1583→
  1584→      span.setAttribute('schedule.horizonWeeks', horizonWeeks);
  1585→      span.setAttribute('schedule.dryRun', dryRun);
  1586→
  1587→      const today = new Date();
  1588→      const horizonStart = today.toISOString().split('T')[0];
  1589→      const horizonEnd = new Date(today.getTime() + horizonWeeks * 7 * 24 * 60 * 60 * 1000)
  1590→        .toISOString()
  1591→        .split('T')[0];
  1592→
  1593→      // Get trains in scope
  1594→      const trainConditions: SQL<unknown>[] = [
  1595→        eq(trains.active, true),
  1596→        eq(trains.fitnessStatus, 'FIT'),
  1597→      ];
  1598→
  1599→      if (fleetId) {
  1600→        trainConditions.push(eq(trains.fleetId, fleetId));
  1601→      }
  1602→      if (depotId) {
  1603→        trainConditions.push(eq(trains.currentDepotId, depotId));
  1604→      }
  1605→
  1606→      const trainsInScope = await this.db.query.trains.findMany({
  1607→        where: and(...trainConditions),
  1608→        with: { fleet: true },
  1609→      });
  1610→
  1611→      span.setAttribute('schedule.trainsInScope', trainsInScope.length);
  1612→
  1613→      // Calculate PM due for all trains
  1614→      const allDueResults: PmDueResult[] = [];
  1615→
  1616→      for (const train of trainsInScope) {
  1617→        const dueResults = await this.calculateAllPmDue(train.id);
  1618→        allDueResults.push(...dueResults);
  1619→      }
  1620→
  1621→      // Filter to PMs due within horizon
  1622→      const pmsDueInHorizon = allDueResults.filter(pm =>
  1623→        pm.complianceWindow.startDate <= horizonEnd &&
  1624→        pm.complianceWindow.endDate >= horizonStart
  1625→      );
  1626→
  1627→      // Sort by priority (overdue first, then by due date)
  1628→      pmsDueInHorizon.sort((a, b) => {
  1629→        if (a.isOverdue && !b.isOverdue) return -1;
  1630→        if (!a.isOverdue && b.isOverdue) return 1;
  1631→        return a.complianceWindow.idealDate.localeCompare(b.complianceWindow.idealDate);
  1632→      });
  1633→
  1634→      span.setAttribute('schedule.pmsDueInHorizon', pmsDueInHorizon.length);
  1635→
  1636→      // Process each PM
  1637→      const scheduled: SchedulingResultItem[] = [];
  1638→      const deferred: SchedulingResultItem[] = [];
  1639→      const blocked: SchedulingResultItem[] = [];
  1640→      const materialWarnings: SchedulingResult['materialWarnings'] = [];
  1641→
  1642→      for (const pmDue of pmsDueInHorizon) {
  1643→        // Check if already scheduled
  1644→        const existingPm = await this.db.query.pmSchedule.findFirst({
  1645→          where: and(
  1646→            eq(pmSchedule.trainId, pmDue.trainId),
  1647→            eq(pmSchedule.pmTypeId, pmDue.pmTypeId),
  1648→            inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS']),
  1649→            isNull(pmSchedule.scenarioId),
  1650→            gte(pmSchedule.targetDate, horizonStart),
  1651→            lte(pmSchedule.targetDate, horizonEnd)
  1652→          ),
  1653→        });
  1654→
  1655→        if (existingPm) {
  1656→          // Skip if locked and we're respecting locks
  1657→          if (respectLocks && existingPm.isLocked) {
  1658→            continue;
  1659→          }
  1660→        }
  1661→
  1662→        // Try to schedule
  1663→        const result = await this.attemptSchedulePm(pmDue, horizonEnd, dryRun);
  1664→
  1665→        if (result.status === 'SCHEDULED') {
  1666→          scheduled.push(result);
  1667→
  1668→          if (result.materialConstraint?.softConstraintWarnings.length) {
  1669→            materialWarnings.push({
  1670→              trainId: pmDue.trainId,
  1671→              trainNumber: pmDue.trainNumber,
  1672→              pmCode: pmDue.pmCode,
  1673→              targetDate: result.targetDate!,
  1674→              warnings: result.materialConstraint.softConstraintWarnings,
  1675→            });
  1676→          }
  1677→        } else if (result.status === 'DEFERRED') {
  1678→          deferred.push(result);
  1679→        } else {
  1680→          blocked.push(result);
  1681→        }
  1682→      }
  1683→
  1684→      // Calculate track utilization
  1685→      const trackUtilization = await this.calculateTrackUtilization(
  1686→        horizonStart,
  1687→        horizonEnd,
  1688→        depotId ?? null
  1689→      );
  1690→
  1691→      const summary = {
  1692→        totalProcessed: pmsDueInHorizon.length,
  1693→        totalScheduled: scheduled.length,
  1694→        totalDeferred: deferred.length,
  1695→        totalBlocked: blocked.length,
  1696→        trackUtilizationPct: trackUtilization,
  1697→      };
  1698→
  1699→      span.setAttribute('result.scheduled', scheduled.length);
  1700→      span.setAttribute('result.deferred', deferred.length);
  1701→      span.setAttribute('result.blocked', blocked.length);
  1702→      span.setAttribute('result.trackUtilization', trackUtilization);
  1703→
  1704→      this.log.info(
  1705→        {
  1706→          horizonStart,
  1707→          horizonEnd,
  1708→          ...summary,
  1709→          fleetId,
  1710→          depotId,
  1711→        },
  1712→        `Tactical scheduling complete: ${scheduled.length} scheduled, ${deferred.length} deferred, ${blocked.length} blocked`
  1713→      );
  1714→
  1715→      return {
  1716→        horizonStart,
  1717→        horizonEnd,
  1718→        scheduled,
  1719→        deferred,
  1720→        blocked,
  1721→        materialWarnings,
  1722→        summary,
  1723→      };
  1724→    });
  1725→  }
  1726→
  1727→  /**
  1728→   * Attempt to schedule a single PM within constraints.
  1729→   */
  1730→  private async attemptSchedulePm(
  1731→    pmDue: PmDueResult,
  1732→    horizonEnd: string,
  1733→    dryRun: boolean
  1734→  ): Promise<SchedulingResultItem> {
  1735→    const explanation: SchedulingExplanation = {
  1736→      mileageTrigger: {
  1737→        intervalKm: null,
  1738→        currentMileageKm: pmDue.currentMileageKm,
  1739→        lastPmMileageKm: pmDue.lastPmMileageKm,
  1740→        kmSinceLastPm: pmDue.lastPmMileageKm !== null
  1741→          ? pmDue.currentMileageKm - pmDue.lastPmMileageKm
  1742→          : null,
  1743→        kmUntilDue: pmDue.kmUntilDue,
  1744→      },
  1745→      timeTrigger: {
  1746→        intervalMonths: null,
  1747→        lastPmDate: pmDue.lastPmDate,
  1748→        daysSinceLastPm: pmDue.lastPmDate
  1749→          ? Math.floor((Date.now() - new Date(pmDue.lastPmDate).getTime()) / (1000 * 60 * 60 * 24))
  1750→          : null,
  1751→        daysUntilDue: pmDue.daysUntilDue,
  1752→      },
  1753→      hierarchySatisfied: {
  1754→        satisfiedBy: null,
  1755→        satisfiedOnDate: null,
  1756→        counterResetFrom: null,
  1757→      },
  1758→      trackSelection: {
  1759→        candidateTracks: 0,
  1760→        selectedTrackId: null,
  1761→        selectionReason: '',
  1762→      },
  1763→      materialCheck: {
  1764→        totalParts: 0,
  1765→        availableParts: 0,
  1766→        blockedParts: 0,
  1767→        warningParts: 0,
  1768→      },
  1769→      laborCapacityCheck: {
  1770→        estimatedHours: 0,
  1771→        weeklyCapacity: 0,
  1772→        currentUtilization: 0,
  1773→        utilizationAfterScheduling: 0,
  1774→        hasCapacity: true,
  1775→      },
  1776→      constraints: [],
  1777→    };
  1778→
  1779→    const warnings: string[] = [];
  1780→
  1781→    // Check unavailability
  1782→    const activeUnavailability = await this.unavailabilityService.getActiveEventsForTrain(pmDue.trainId);
  1783→    const blockingEvent = activeUnavailability.find(e => e.blocksPmScheduling);
  1784→
  1785→    if (blockingEvent) {
  1786→      explanation.constraints.push(`Blocked by unavailability: ${blockingEvent.eventType}`);
  1787→
  1788→      return {
  1789→        trainId: pmDue.trainId,
  1790→        trainNumber: pmDue.trainNumber,
  1791→        pmTypeId: pmDue.pmTypeId,
  1792→        pmCode: pmDue.pmCode,
  1793→        status: 'BLOCKED',
  1794→        targetDate: null,
  1795→        targetMileageKm: null,
  1796→        trackAllocation: null,
  1797→        materialConstraint: null,
  1798→        laborCapacity: null,
  1799→        complianceWindow: pmDue.complianceWindow,
  1800→        deferralReason: `Train has active unavailability: ${blockingEvent.eventType}`,
  1801→        warnings,
  1802→        explanation,
  1803→      };
  1804→    }
  1805→
  1806→    // Determine ideal target date (within horizon)
  1807→    let targetDate = pmDue.complianceWindow.idealDate;
  1808→    if (targetDate > horizonEnd) {
  1809→      targetDate = horizonEnd;
  1810→    }
  1811→    if (targetDate < new Date().toISOString().split('T')[0]) {
  1812→      targetDate = new Date().toISOString().split('T')[0];
  1813→    }
  1814→
  1815→    // Check service demand
  1816→    const demandCheck = await this.serviceDemandService.canScheduleTrainForMaintenance(
  1817→      pmDue.trainId,
  1818→      targetDate
  1819→    );
  1820→
  1821→    if (!demandCheck.canSchedule) {
  1822→      // Try alternative dates within compliance window
  1823→      const alternativeDate = await this.findAlternativeDateForServiceDemand(
  1824→        pmDue.trainId,
  1825→        pmDue.complianceWindow.startDate,
  1826→        pmDue.complianceWindow.endDate
  1827→      );
  1828→
  1829→      if (!alternativeDate) {
  1830→        explanation.constraints.push(`Service demand violation: ${demandCheck.validation.message}`);
  1831→
  1832→        return {
  1833→          trainId: pmDue.trainId,
  1834→          trainNumber: pmDue.trainNumber,
  1835→          pmTypeId: pmDue.pmTypeId,
  1836→          pmCode: pmDue.pmCode,
  1837→          status: 'DEFERRED',
  1838→          targetDate: null,
  1839→          targetMileageKm: null,
  1840→          trackAllocation: null,
  1841→          materialConstraint: null,
  1842→          laborCapacity: null,
  1843→          complianceWindow: pmDue.complianceWindow,
  1844→          deferralReason: demandCheck.validation.message,
  1845→          warnings,
  1846→          explanation,
  1847→        };
  1848→      }
  1849→
  1850→      targetDate = alternativeDate;
  1851→      warnings.push(`Rescheduled to ${alternativeDate} due to service demand constraints`);
  1852→    }
  1853→
  1854→    // Get train's depot
  1855→    const train = await this.db.query.trains.findFirst({
  1856→      where: eq(trains.id, pmDue.trainId),
  1857→    });
  1858→
  1859→    const depotId = train?.currentDepotId ?? train?.homeDepotId;
  1860→    if (!depotId) {
  1861→      explanation.constraints.push('No depot available for train');
  1862→
  1863→      return {
  1864→        trainId: pmDue.trainId,
  1865→        trainNumber: pmDue.trainNumber,
  1866→        pmTypeId: pmDue.pmTypeId,
  1867→        pmCode: pmDue.pmCode,
  1868→        status: 'BLOCKED',
  1869→        targetDate: null,
  1870→        targetMileageKm: null,
  1871→        trackAllocation: null,
  1872→        materialConstraint: null,
  1873→        laborCapacity: null,
  1874→        complianceWindow: pmDue.complianceWindow,
  1875→        deferralReason: 'Train has no assigned depot',
  1876→        warnings,
  1877→        explanation,
  1878→      };
  1879→    }
  1880→
  1881→    // Get PM type for track duration
  1882→    const pmType = await this.db.query.pmTypes.findFirst({
  1883→      where: eq(pmTypes.id, pmDue.pmTypeId),
  1884→    });
  1885→
  1886→    const trackDuration = pmType?.minTrackDays ?? 1;
  1887→
  1888→    // Find suitable tracks
  1889→    const suitableTracks = await this.findSuitableTracks(
  1890→      pmDue.pmTypeId,
  1891→      depotId,
  1892→      targetDate,
  1893→      trackDuration
  1894→    );
  1895→
  1896→    explanation.trackSelection.candidateTracks = suitableTracks.length;
  1897→
  1898→    if (suitableTracks.length === 0) {
  1899→      explanation.constraints.push('No suitable tracks available');
  1900→      explanation.trackSelection.selectionReason = 'No tracks match requirements or all are occupied';
  1901→
  1902→      return {
  1903→        trainId: pmDue.trainId,
  1904→        trainNumber: pmDue.trainNumber,
  1905→        pmTypeId: pmDue.pmTypeId,
  1906→        pmCode: pmDue.pmCode,
  1907→        status: 'DEFERRED',
  1908→        targetDate: null,
  1909→        targetMileageKm: null,
  1910→        trackAllocation: null,
  1911→        materialConstraint: null,
  1912→        laborCapacity: null,
  1913→        complianceWindow: pmDue.complianceWindow,
  1914→        deferralReason: 'No suitable tracks available',
  1915→        warnings,
  1916→        explanation,
  1917→      };
  1918→    }
  1919→
  1920→    const selectedTrack = suitableTracks[0];
  1921→    explanation.trackSelection.selectedTrackId = selectedTrack.trackId;
  1922→    explanation.trackSelection.selectionReason = selectedTrack.hasAllCapabilities
  1923→      ? 'Track has all required capabilities'
  1924→      : `Track missing: ${selectedTrack.missingCapabilities.join(', ')}`;
  1925→
  1926→    if (!selectedTrack.hasAllCapabilities) {
  1927→      warnings.push(`Selected track missing capabilities: ${selectedTrack.missingCapabilities.join(', ')}`);
  1928→    }
  1929→
  1930→    // Check material availability
  1931→    const materialResult = await this.checkMaterialAvailability(
  1932→      pmDue.pmTypeId,
  1933→      depotId,
  1934→      targetDate
  1935→    );
  1936→
  1937→    explanation.materialCheck.totalParts = materialResult.reservations.length +
  1938→      materialResult.hardConstraintViolations.length +
  1939→      materialResult.softConstraintWarnings.length;
  1940→    explanation.materialCheck.availableParts = materialResult.reservations.length;
  1941→    explanation.materialCheck.blockedParts = materialResult.hardConstraintViolations.length;
  1942→    explanation.materialCheck.warningParts = materialResult.softConstraintWarnings.length;
  1943→
  1944→    if (materialResult.isBlocked) {
  1945→      const blockingParts = materialResult.hardConstraintViolations
  1946→        .map(v => v.partNumber)
  1947→        .join(', ');
  1948→
  1949→      explanation.constraints.push(`Blocked by material constraint: ${blockingParts}`);
  1950→
  1951→      return {
  1952→        trainId: pmDue.trainId,
  1953→        trainNumber: pmDue.trainNumber,
  1954→        pmTypeId: pmDue.pmTypeId,
  1955→        pmCode: pmDue.pmCode,
  1956→        status: 'BLOCKED',
  1957→        targetDate: null,
  1958→        targetMileageKm: null,
  1959→        trackAllocation: selectedTrack,
  1960→        materialConstraint: materialResult,
  1961→        laborCapacity: null,
  1962→        complianceWindow: pmDue.complianceWindow,
  1963→        deferralReason: `Blocking materials not available: ${blockingParts}`,
  1964→        warnings,
  1965→        explanation,
  1966→      };
  1967→    }
  1968→
  1969→    if (materialResult.softConstraintWarnings.length > 0) {
  1970→      const warningParts = materialResult.softConstraintWarnings
  1971→        .map(w => w.partNumber)
  1972→        .join(', ');
  1973→      warnings.push(`Material warning: ${warningParts} may not be available`);
  1974→    }
  1975→
  1976→    // Calculate target mileage
  1977→    const dailyKm = await this.getAverageDailyKm(pmDue.trainId);
  1978→    const daysUntilTarget = Math.ceil(
  1979→      (new Date(targetDate).getTime() - Date.now()) / (1000 * 60 * 60 * 24)
  1980→    );
  1981→    const targetMileageKm = pmDue.currentMileageKm + (daysUntilTarget * dailyKm);
  1982→
  1983→    // Create the PM schedule if not dry run
  1984→    if (!dryRun) {
  1985→      try {
  1986→        await this.schedulePm({
  1987→          trainId: pmDue.trainId,
  1988→          pmTypeId: pmDue.pmTypeId,
  1989→          targetDate,
  1990→          assignedDepotId: depotId,
  1991→          assignedTrackId: selectedTrack.trackId,
  1992→          skipMaterialCheck: true, // Already checked
  1993→          skipServiceDemandCheck: true, // Already checked
  1994→        });
  1995→      } catch (error) {
  1996→        const errorMessage = error instanceof Error ? error.message : 'Unknown error';
  1997→        explanation.constraints.push(`Scheduling failed: ${errorMessage}`);
  1998→
  1999→        return {
  2000→          trainId: pmDue.trainId,
  2001→          trainNumber: pmDue.trainNumber,
  2002→          pmTypeId: pmDue.pmTypeId,
  2003→          pmCode: pmDue.pmCode,
  2004→          status: 'BLOCKED',
  2005→          targetDate: null,
  2006→          targetMileageKm: null,
  2007→          trackAllocation: selectedTrack,
  2008→          materialConstraint: materialResult,
  2009→          laborCapacity: null,
  2010→          complianceWindow: pmDue.complianceWindow,
  2011→          deferralReason: errorMessage,
  2012→          warnings,
  2013→          explanation,
  2014→        };
  2015→      }
  2016→    }
  2017→
  2018→    return {
  2019→      trainId: pmDue.trainId,
  2020→      trainNumber: pmDue.trainNumber,
  2021→      pmTypeId: pmDue.pmTypeId,
  2022→      pmCode: pmDue.pmCode,
  2023→      status: 'SCHEDULED',
  2024→      targetDate,
  2025→      targetMileageKm: Math.round(targetMileageKm),
  2026→      trackAllocation: selectedTrack,
  2027→      materialConstraint: materialResult,
  2028→      laborCapacity: null,
  2029→      complianceWindow: pmDue.complianceWindow,
  2030→      deferralReason: null,
  2031→      warnings,
  2032→      explanation,
  2033→    };
  2034→  }
