  2091→  private async getLastCompletedPm(
  2092→    trainId: string,
  2093→    pmTypeId: string
  2094→  ): Promise<PmScheduleRecord | null> {
  2095→    const lastPm = await this.db.query.pmSchedule.findFirst({
  2096→      where: and(
