  2103→    });
  2104→
  2105→    return lastPm ?? null;
  2106→  }
  2107→
  2108→  /**
  2109→   * Get average daily km for a train from recent mileage readings.
  2110→   */
  2111→  private async getAverageDailyKm(trainId: string): Promise<number> {
  2112→    const thirtyDaysAgo = new Date();
  2113→    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
  2114→
  2115→    const readings = await this.db
  2116→      .select({
  2117→        avgDailyKm: sql<number>`AVG(${mileageReadings.dailyKm})`,
  2118→      })
  2119→      .from(mileageReadings)
  2120→      .where(
  2121→        and(
  2122→          eq(mileageReadings.trainId, trainId),
  2123→          gte(mileageReadings.readingDate, thirtyDaysAgo.toISOString().split('T')[0]),
  2124→          eq(mileageReadings.validationStatus, 'VALID')
  2125→        )
  2126→      );
